// Process real Claude API response and add pass-through data
// Wraps real API response to match stub format for downstream compatibility
const claudeResponse = $input.first().json;
const inputData = $('Use Stubs for IdeaSynthesizer?').first().json;
const cluster = inputData.cluster;
const periodData = inputData._periodData;
const thresholds = inputData._thresholds || {};

// Handle case where there's no valid cluster (shouldn't happen in real branch, but be safe)
if (inputData.noValidClusters || !cluster) {
  return [{
    json: {
      content: [{ type: 'text', text: JSON.stringify({ skip: true, reason: 'No valid clusters' }) }],
      _periodData: periodData,
      _cluster: null,
      _skip: true,
      _thresholds: thresholds,
      _agents: inputData._agents
    }
  }];
}

const insights = cluster.insights || [];
const topic = cluster.topic;

// Collect all insight IDs for this cluster
const derivedFromInsightIds = insights.map(i => i.id);

// Collect all citations from cluster insights
const allCitations = [];
for (const insight of insights) {
  if (insight.citations && Array.isArray(insight.citations)) {
    allCitations.push(...insight.citations);
  }
}
const uniqueCitations = [...new Set(allCitations)];

// Return in same format as stub for downstream node compatibility
return [{
  json: {
    content: claudeResponse.content,
    _periodData: periodData,
    _cluster: cluster,
    _derivedFromInsightIds: derivedFromInsightIds,
    _citations: uniqueCitations,
    _topic: topic,
    _thresholds: thresholds,
    _agents: inputData._agents
  }
}];

// Parse and validate LLM output for project idea
// Uses thresholds from config for scoring gates
// Handles both stub and real API responses
const input = $input.first().json;
const thresholds = input._thresholds || {};

// Get thresholds from config
const minFeasibility = thresholds.minFeasibility || 50;
const minImpact = thresholds.minImpact || 50;

// Check for skip signal
if (input._skip) {
  return [{
    json: {
      skip: true,
      reason: 'No valid clusters to process',
      _thresholds: thresholds
    }
  }];
}

let idea;
try {
  let text = input.content[0].text;

  // Strip markdown code blocks if present (Claude often wraps JSON in ```json...```)
  text = text.trim();
  if (text.startsWith('```')) {
    // Remove opening fence (```json or ```)
    text = text.replace(/^```(?:json)?\s*\n?/, '');
    // Remove closing fence
    text = text.replace(/\n?```\s*$/, '');
  }

  idea = JSON.parse(text.trim());
} catch (e) {
  console.log('Parse Idea error:', e.message);
  console.log('Raw text:', input.content?.[0]?.text?.substring(0, 500));
  return [{
    json: {
      skip: true,
      reason: 'Failed to parse LLM output: ' + e.message,
      validationErrors: ['JSON parse error: ' + e.message],
      _thresholds: thresholds
    }
  }];
}

// Skip if idea parsing returned skip signal
if (idea.skip) {
  return [{
    json: {
      skip: true,
      reason: idea.reason || 'Skipped by LLM',
      _thresholds: thresholds
    }
  }];
}

// Validate required fields
const requiredFields = [
  'problem_statement',
  'threat_model',
  'affected_groups',
  'proposed_solution',
  'mvp_scope',
  'misuse_risks',
  'feasibility_score',
  'impact_score'
];

const errors = [];
for (const field of requiredFields) {
  if (!idea[field]) {
    errors.push(`Missing required field: ${field}`);
  }
}

// Validate score ranges
if (typeof idea.feasibility_score !== 'number' || idea.feasibility_score < 0 || idea.feasibility_score > 100) {
  errors.push('feasibility_score must be 0-100');
}
if (typeof idea.impact_score !== 'number' || idea.impact_score < 0 || idea.impact_score > 100) {
  errors.push('impact_score must be 0-100');
}

// Validate affected_groups is array
if (!Array.isArray(idea.affected_groups) || idea.affected_groups.length === 0) {
  errors.push('affected_groups must be non-empty array');
}

if (errors.length > 0) {
  console.log('Idea validation errors:', errors);
  return [{
    json: {
      skip: true,
      reason: 'Validation failed',
      validationErrors: errors,
      rawIdea: idea,
      _thresholds: thresholds
    }
  }];
}

// Normalize optional array fields
idea.technical_dependencies = idea.technical_dependencies || [];
idea.suggested_stack = idea.suggested_stack || [];
idea.prior_art = idea.prior_art || [];
idea.open_questions = idea.open_questions || [];

// Use thresholds from config for the gate check
const meetsThreshold = idea.feasibility_score >= minFeasibility && idea.impact_score >= minImpact;

console.log(`Idea scores: feasibility=${idea.feasibility_score} (min: ${minFeasibility}), impact=${idea.impact_score} (min: ${minImpact}) => meetsThreshold=${meetsThreshold}`);

return [{
  json: {
    idea,
    derivedFromInsightIds: input._derivedFromInsightIds,
    citations: input._citations,
    topic: input._topic,
    cluster: input._cluster,
    meetsThreshold,
    skip: false,
    _thresholds: thresholds,
    _usedThresholds: {
      minFeasibility,
      minImpact
    }
  }
}];

// Build INSERT query for project_ideas table with proper escaping
const data = $input.first().json;
const idea = data.idea;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

function formatPgArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  const escaped = arr.map(s => '"' + String(s).replace(/"/g, '\\"').replace(/'/g, "''") + '"');
  return "'{" + escaped.join(',') + "}'";
}

function formatUuidArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  return "'{" + arr.join(',') + "}'";
}

const query = `INSERT INTO project_ideas (
  derived_from_insight_ids,
  problem_statement,
  threat_model,
  affected_groups,
  proposed_solution,
  mvp_scope,
  misuse_risks,
  feasibility_score,
  impact_score,
  technical_dependencies,
  suggested_stack,
  prior_art,
  open_questions,
  status
) VALUES (
  ${formatUuidArray(data.derivedFromInsightIds)},
  ${escapeStr(idea.problem_statement)},
  ${escapeStr(idea.threat_model)},
  ${formatPgArray(idea.affected_groups)},
  ${escapeStr(idea.proposed_solution)},
  ${escapeStr(idea.mvp_scope)},
  ${escapeStr(idea.misuse_risks)},
  ${idea.feasibility_score},
  ${idea.impact_score},
  ${formatPgArray(idea.technical_dependencies)},
  ${formatPgArray(idea.suggested_stack)},
  ${formatPgArray(idea.prior_art)},
  ${formatPgArray(idea.open_questions)},
  'new'
) RETURNING id, feasibility_score, impact_score, created_at`;

return [{
  json: {
    query,
    _ideaData: {
      idea,
      topic: data.topic,
      derivedFromInsightIds: data.derivedFromInsightIds,
      citations: data.citations,
      cluster: data.cluster
    }
  }
}];

// Merge insert result with idea data and cluster info for issue creation
const insertResult = $input.first().json;
const ideaData = $('Build Idea Query').first().json._ideaData;
const validateData = $('Validate Idea Output').first().json;
const thresholds = validateData._thresholds || {};

return [{
  json: {
    ideaId: insertResult.id,
    feasibilityScore: insertResult.feasibility_score,
    impactScore: insertResult.impact_score,
    createdAt: insertResult.created_at,
    idea: ideaData.idea,
    topic: ideaData.topic,
    derivedFromInsightIds: ideaData.derivedFromInsightIds,
    citations: ideaData.citations,
    insightCount: ideaData.cluster ? ideaData.cluster.insightCount : 0,
    cluster: ideaData.cluster,
    _thresholds: thresholds
  }
}];

// Prepare GitHub issue title and body
// Uses actual published_url from insights when available

const data = $input.first().json;
const idea = data.idea;
const cluster = data.cluster;
const thresholds = data._thresholds || {};

// Build issue title (truncate cleanly at word boundary)
let titleText = idea.problem_statement;
if (titleText.length > 80) {
  titleText = titleText.substring(0, 77).replace(/\s+\S*$/, '') + '...';
}
const issueTitle = `[Idea] ${titleText}`;

// Build issue body markdown
const affectedGroupsList = idea.affected_groups.map(g => `- ${g}`).join('\n');
const dependenciesList = (idea.technical_dependencies || []).map(d => `- ${d}`).join('\n') || '_None specified_';
const stackList = (idea.suggested_stack || []).map(s => `- ${s}`).join('\n') || '_None specified_';
const priorArtList = (idea.prior_art || []).map(p => `- ${p}`).join('\n') || '_None specified_';
const questionsList = (idea.open_questions || []).map(q => `- ${q}`).join('\n') || '_None specified_';

// Build derived insights links using actual published_url from cluster insights
let insightLinks = '_No insights linked_';
if (cluster && cluster.insights && cluster.insights.length > 0) {
  insightLinks = cluster.insights.map(insight => {
    const url = insight.published_url || `https://libertas.fgu.tech/signals/${insight.id}`;
    return `- [${insight.title}](${url})`;
  }).join('\n');
}

const issueBody = `## Problem Statement

${idea.problem_statement}

## Threat Model

${idea.threat_model}

## Affected Groups

${affectedGroupsList}

## Proposed Solution

${idea.proposed_solution}

## MVP Scope

${idea.mvp_scope}

## Misuse Risks

${idea.misuse_risks}

## Scores

- **Feasibility:** ${idea.feasibility_score}/100
- **Impact:** ${idea.impact_score}/100

## Technical Dependencies

${dependenciesList}

## Suggested Stack

${stackList}

## Prior Art

${priorArtList}

## Open Questions

${questionsList}

## Derived From Insights

${insightLinks}

---
*Auto-generated by Libertas Workflow D*
*Idea ID: \`${data.ideaId}\`*`;

return [{
  json: {
    issueTitle,
    issueBody,
    ideaId: data.ideaId,
    feasibilityScore: data.feasibilityScore,
    impactScore: data.impactScore,
    topic: data.topic,
    _thresholds: thresholds
  }
}];

// STUB: Simulate GitHub issue creation response
// Returns mock issue data in same format as real API wrapper

const data = $input.first().json;

// Simulate GitHub issue creation response
const stubIssueNumber = 100 + Math.floor(Math.random() * 900);
const stubIssueUrl = `https://github.com/FGUTech/libertas/issues/${stubIssueNumber}`;

console.log(`[STUB] Created mock GitHub issue #${stubIssueNumber} for idea ${data.ideaId}`);

return [{
  json: {
    html_url: stubIssueUrl,
    number: stubIssueNumber,
    title: data.issueTitle,
    state: 'open',
    _ideaId: data.ideaId,
    _isStub: true
  }
}];

// Process real GitHub API response and add pass-through data
const githubResponse = $input.first().json;
const prepareData = $('Prepare GitHub Issue').first().json;

return [{
  json: {
    html_url: githubResponse.html_url,
    number: githubResponse.number,
    title: githubResponse.title,
    state: githubResponse.state,
    _ideaId: prepareData.ideaId,
    _isStub: false
  }
}];

// Handle errors from GitHub API call
// Provides graceful degradation when API fails

const error = $input.first().json;
const prepareData = $('Prepare GitHub Issue').first().json;

console.log('GitHub API error:', JSON.stringify(error));

// Return null issue URL to allow workflow to continue
// The idea is still saved, just without GitHub issue
return [{
  json: {
    html_url: null,
    number: null,
    title: prepareData.issueTitle,
    state: 'error',
    _ideaId: prepareData.ideaId,
    _isStub: false,
    _apiError: true,
    _errorMessage: 'GitHub issue creation failed - will retry later'
  }
}];

// Build UPDATE query to set github_issue_url on the project idea
// Handles both stub and real GitHub API responses (uses html_url field)
const data = $input.first().json;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

// Use html_url from GitHub API response format
const issueUrl = data.html_url;

const query = `UPDATE project_ideas 
SET github_issue_url = ${escapeStr(issueUrl)},
    updated_at = NOW()
WHERE id = ${escapeStr(data._ideaId)}::uuid
RETURNING id, github_issue_url`;

console.log(`Updating idea ${data._ideaId} with GitHub issue URL: ${issueUrl || 'NULL'}`);

return [{
  json: {
    query,
    _issueData: data
  }
}];

// Final summary for successfully processed idea
const updateResult = $input.first().json;
const issueData = $('Build Update Query').first().json._issueData;

return [{
  json: {
    success: true,
    ideaId: updateResult.id,
    githubIssueUrl: updateResult.github_issue_url,
    githubIssueNumber: issueData.number,
    topic: $('Prepare GitHub Issue').first().json.topic,
    feasibilityScore: $('Prepare GitHub Issue').first().json.feasibilityScore,
    impactScore: $('Prepare GitHub Issue').first().json.impactScore,
    wasStub: issueData._isStub,
    hadError: issueData._apiError || false,
    processedAt: new Date().toISOString()
  }
}];

// Log ideas that were skipped due to low scores
const data = $input.first().json;
const thresholds = data._thresholds || {};
const usedThresholds = data._usedThresholds || {};

const minFeasibility = usedThresholds.minFeasibility || thresholds.minFeasibility || 50;
const minImpact = usedThresholds.minImpact || thresholds.minImpact || 50;

const reason = data.skip 
  ? (data.reason || 'Skipped') 
  : `Scores below threshold (feasibility >= ${minFeasibility} AND impact >= ${minImpact} required)`;

const scores = data.idea ? {
  feasibility: data.idea.feasibility_score,
  impact: data.idea.impact_score
} : null;

console.log(`Skipped idea generation: ${reason}`);
if (data.validationErrors) {
  console.log('Validation errors:', data.validationErrors);
}

return [{
  json: {
    success: true,
    skipped: true,
    reason,
    scores,
    validationErrors: data.validationErrors || null,
    topic: data.topic || null,
    processedAt: new Date().toISOString(),
    usedThresholds: {
      minFeasibility,
      minImpact
    }
  }
}];

// Handle case when no high-signal insights were found
const data = $input.first().json;
const thresholds = data._thresholds || {};

console.log(`No high-signal insights found for idea generation. Criteria: freedom_relevance_score >= ${data.minRelevanceScore}, status = published, last ${thresholds.lookbackDays || 7} days, not already used.`);

return [{
  json: {
    executedAt: new Date().toISOString(),
    success: true,
    skipped: true,
    reason: 'No eligible high-signal insights found',
    criteria: {
      minRelevanceScore: data.minRelevanceScore,
      periodStartSQL: data.periodStartSQL,
